-Value *LibCallSimplifier::optimizeStrLen(CallInst *CI, IRBuilderBase &B) {
-  if (Value *V = optimizeStringLength(CI, B, 8))
-    return V;
-  annotateNonNullNoUndefBasedOnAccess(CI, 0);
