-Value *LibCallSimplifier::optimizeStrNLen(CallInst *CI, IRBuilderBase &B) {
-  Value *Bound = CI->getArgOperand(1);
-  if (Value *V = optimizeStringLength(CI, B, 8, Bound))
-    return V;
